@app.route("/", methods=["POST"])
def webhook_handler():
    # 1. Basic validation: Ensure it's a POST request
    if request.method != "POST":
        print(f"ERROR: Received {request.method} request, expected POST.")
        abort(405)  # Method Not Allowed

    # 2. Get the raw request body
    # It's crucial to get the raw body before any parsing, as the signature
    # is often computed over the exact raw bytes.
    request_body = request.get_data()
    
    # 3. Extract relevant headers for signature validation
    # Adapt these header names based on your partner's specific implementation.
