        # expected_signature_bytes = base64.b64decode(signature_header)
        
        # Calculate HMAC-SHA256
        calculated_signature_bytes = hmac.new(
            secret_bytes,
            msg=request_body,
            digestmod=hashlib.sha256
        ).digest()
        
        # The partner's signature might be hex encoded.
        calculated_signature = calculated_signature_bytes.hex()
        
        # Perform a secure comparison (prevents timing attacks)
        # Some partners might send a base64 encoded signature, then you'd compare bytes:
        # if not hmac.compare_digest(calculated_signature_bytes, base64.b64decode(signature_header)):
        
